import React, { forwardRef, useState } from 'react'
import { ListItem, useOverlay } from '@fs/zion-ui'
import { PlaceSuggestion } from '@fs/zion-icon'
import { trackLink } from '@fs/zion-analytics'
import { useTranslation } from 'react-i18next'
// NOTE: Static import of zion-provisional-place means the module is loaded upfront.
// Future optimization: consider dynamic import (React.lazy) to defer loading until overlay opens.
/* eslint-disable-next-line @nx/enforce-module-boundaries -- ProvisionalPlace is internal dependency */
import ProvisionalPlace from '@fs/zion-provisional-place'
import StandardSuggestCore from '../standard-suggest/StandardSuggestCore'
import type { StandardSuggestCoreProps } from '../standard-suggest/StandardSuggestCore'
import useProposedPlaces from './useProposedPlaces'
import type { PlaceSuggestionItem } from '../types/place'
import type { SuggestionItem } from '../types/common'

const trackLinkClick = {
  to: 'familysearch.org',
  action: 'click_action',
}

type ProvisionalPlaceResponse = {
  status: number
  data?: {
    placeRep?: unknown
  }
}

type ProposeNewPlaceSuggestProps = {
  /** Label for the input field */
  label?: string | null
  /** Callback when a suggestion is selected */
  onSuggestionSelected: (suggestion: PlaceSuggestionItem | null, filteredSuggestions?: PlaceSuggestionItem[]) => void
  /** Initial selected item */
  initialSelectedItem?: PlaceSuggestionItem | null
} & Omit<
  StandardSuggestCoreProps,
  | 'type'
  | 'onSuggestionSelected'
  | 'label'
  | 'proposedSuggestions'
  | 'lastResort'
  | 'onInputTextChange'
  | 'selectedItem'
>

const ProposeNewPlaceSuggest = forwardRef<HTMLInputElement, ProposeNewPlaceSuggestProps>(
  function ProposeNewPlaceSuggest({ label, onSuggestionSelected, ...props }, ref) {
    const { t } = useTranslation()
    const [selectedItem, setSelectedItem] = useState<PlaceSuggestionItem | null>(
      (props.initialSelectedItem as PlaceSuggestionItem) || null
    )
    const [inputText, setInputText] = useState('')
    const provisionalOverlay = useOverlay()
    const { proposedSuggestions, reloadProposedSuggestions, createSuggestionFromProposedPlaceRep } = useProposedPlaces()

    const lastResort = {
      key: 'LAST_RESORT',
      primaryText: t('place-suggest.new-place.label', 'Suggest New Place'),
      startElement: React.createElement(ListItem.Icon, { Icon: PlaceSuggestion }),
      onClick: () => {
        trackLink({ ...trackLinkClick, name: 'PlaceSuggest:Suggest New Place:Click' })
        provisionalOverlay.open()
      },
    }
    const handleProvisionalSubmit = (_values: unknown, resp: ProvisionalPlaceResponse): void => {
      const placeRep = resp?.data?.placeRep
      if (resp?.status === 201) {
        reloadProposedSuggestions()
        const newSelectedItem = createSuggestionFromProposedPlaceRep(placeRep as never)
        setSelectedItem(newSelectedItem)
        onSuggestionSelected(newSelectedItem)
      }
      provisionalOverlay.close()
    }

    const handleExistingPlaceSelect = (place: PlaceSuggestionItem): void => {
      setSelectedItem(place)
      onSuggestionSelected(place)
      provisionalOverlay.close()
      trackLink({ ...trackLinkClick, name: 'ProvisionalPlace:Existing Place Select:Click' })
    }
    const handleSuggestionSelect = (suggestion: SuggestionItem | null, filteredSuggestions: SuggestionItem[]): void => {
      if (suggestion?.key === 'LAST_RESORT') {
        trackLink({ ...trackLinkClick, name: 'PlaceSuggest:Suggest New Place:Click' })
        setSelectedItem(null)
        setInputText('')
        provisionalOverlay.open()
      } else {
        setSelectedItem(suggestion as PlaceSuggestionItem)
        onSuggestionSelected(suggestion as PlaceSuggestionItem, filteredSuggestions as PlaceSuggestionItem[])
        trackLink({ ...trackLinkClick, name: 'PlaceSuggest:Standard Place Select:Click' })
      }
    }
    return (
      <>
        <StandardSuggestCore
          type="place"
          label={label}
          onSuggestionSelected={handleSuggestionSelect}
          proposedSuggestions={proposedSuggestions as never}
          lastResort={lastResort}
          onInputTextChange={setInputText}
          selectedItem={selectedItem as never}
          {...props}
          ref={ref}
        />
        <ProvisionalPlace
          overlay={provisionalOverlay}
          onSubmit={handleProvisionalSubmit}
          onCancel={() => provisionalOverlay.close()}
          onSelectExistingPlace={(place: PlaceSuggestionItem) => handleExistingPlaceSelect(place)}
          placeName={inputText}
          isProposed
        />
      </>
    )
  }
)

export default ProposeNewPlaceSuggest
